class IsPhoneNumber(DirtyEquals[str]):
    """
    A class that checks if a value is a phone number, optionally restricting validation to a
    specific country's formatting rules.
    """

    _NATIONAL_PATTERNS = {
        'US': re.compile(r'\d{10}'),
        'GB': re.compile(r'0\d{10}'),
    }
    _INTERNATIONAL_PATTERNS = {
        'US': re.compile(r'1\d{10}'),
        'GB': re.compile(r'44\d{10}'),
    }
    _GENERIC_PATTERN = re.compile(r'\d{7,15}')
    _ALLOWED_CHARS_PATTERN = re.compile(r'\+?[\d\s\-.()]+')

    def __init__(self, country_code: Optional[str] = None):
        """
        Args:
            country_code: The country to validate the phone number against (e.g. `'US'`, `'GB'`), if
                omitted, generic phone number validation is performed. Countries without dedicated
                rules fall back to generic international validation.

        ```py title="IsPhoneNumber"
        from dirty_equals import IsPhoneNumber

        assert '+1-555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber('US')
        assert '555-123-4567' != IsPhoneNumber('GB')
        assert '020 7946 0958' == IsPhoneNumber('GB')
        assert '+44 20 7946 0958' == IsPhoneNumber('GB')
        assert 1234567890 != IsPhoneNumber('US')
        ```
        """
        self.country_code = country_code.upper() if country_code else None
        super().__init__(self.country_code or plain_repr('*'))

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False

        value = other.strip()
        if not self._ALLOWED_CHARS_PATTERN.fullmatch(value):
            return False

        is_international = value.startswith('+')
        digits = re.sub(r'\D', '', value)
        if not digits:
            return False

        if self.country_code is None:
            return bool(self._GENERIC_PATTERN.fullmatch(digits))

        national_pattern = self._NATIONAL_PATTERNS.get(self.country_code)
        international_pattern = self._INTERNATIONAL_PATTERNS.get(self.country_code)

        if national_pattern is None or international_pattern is None:
            # unknown country code: fall back to generic international validation
            return is_international and bool(self._GENERIC_PATTERN.fullmatch(digits))

        if is_international:
            return bool(international_pattern.fullmatch(digits))
        else:
            return bool(national_pattern.fullmatch(digits))"}
